30	const MIN_DRAWER_HEIGHT = 180;
31	const MAX_DRAWER_HEIGHT_RATIO = 0.75;
32	
33	function maxDrawerHeight(): number {
34	  if (typeof window === "undefined") return DEFAULT_THREAD_TERMINAL_HEIGHT;
35	  return Math.max(MIN_DRAWER_HEIGHT, Math.floor(window.innerHeight * MAX_DRAWER_HEIGHT_RATIO));
36	}
37	
38	function clampDrawerHeight(height: number): number {
39	  const safeHeight = Number.isFinite(height) ? height : DEFAULT_THREAD_TERMINAL_HEIGHT;
40	  const maxHeight = maxDrawerHeight();
41	  return Math.min(Math.max(Math.round(safeHeight), MIN_DRAWER_HEIGHT), maxHeight);
42	}
