    secondary: "rgba(130, 160, 220, 0.06)",
    secondaryForeground: "#e0e4f0",
    destructive: "#f87171",
    destructiveForeground: "#fca5a5",
  },
};

const BUILT_IN_THEMES: readonly Theme[] = [t3Light, t3Dark, t3Midnight];

const THEME_MAP = new Map<ThemeId, Theme>(BUILT_IN_THEMES.map((t) => [t.id, t]));

/** All valid theme IDs. */
const THEME_IDS = new Set<string>(BUILT_IN_THEMES.map((t) => t.id));

// ---------------------------------------------------------------------------
// Public helpers
// ---------------------------------------------------------------------------

/** Returns an array of all built-in themes. */
export function getBuiltInThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/** Looks up a theme by ID. Returns `undefined` for unknown IDs. */
export function getThemeById(id: ThemeId): Theme | undefined {
  return THEME_MAP.get(id);
}

/** Type guard — returns `true` when `value` is a valid `ThemeId`. */
export function isThemeId(value: unknown): value is ThemeId {
  return typeof value === "string" && THEME_IDS.has(value);
}

