/** Returns an array of all built-in themes. */
export function getBuiltInThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/** Looks up a theme by ID. Returns `undefined` for unknown IDs. */
export function getThemeById(id: ThemeId): Theme | undefined {
