import { getBuiltInThemes } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";
import { cn } from "../lib/utils";

const builtInThemes = getBuiltInThemes();

export function ThemeSelector() {
  const { theme, setTheme, resolvedTheme } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
      {/* System option */}
      <button
        type="button"
        role="radio"
        aria-checked={theme === "system"}
        className={cn(
          "flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors",
          theme === "system"
            ? "border-primary/60 bg-primary/8 text-foreground"
            : "border-border bg-background text-muted-foreground hover:bg-accent",
        )}
        onClick={() => setTheme("system")}
      >
        <span className="flex items-center gap-3">
          {/* Two-tone swatch representing light + dark */}
          <span
            className="flex h-8 w-12 shrink-0 overflow-hidden rounded-md border border-border"
            aria-hidden="true"
          >
            <span className="w-1/2 bg-white" />
            <span className="w-1/2 bg-neutral-900" />
          </span>
          <span className="flex flex-col">
            <span className="text-sm font-medium">System</span>
            <span className="text-xs">Match your OS appearance setting.</span>
          </span>
        </span>
        {theme === "system" ? (
          <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Selected
          </span>
        ) : null}
      </button>

      {/* Built-in themes */}
      {builtInThemes.map((t) => {
        const selected = theme === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={cn(
              "flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            )}
            onClick={() => setTheme(t.id)}
          >
            <span className="flex items-center gap-3">
              {/* Miniature preview swatch */}
              <span
                className="flex h-8 w-12 shrink-0 overflow-hidden rounded-md border border-border"
                aria-hidden="true"
              >
                <span
                  className="w-1/3"
                  style={{ background: t.colors.sidebarBackground }}
                />
                <span className="flex w-2/3 flex-col">
                  <span
                    className="flex-1"
                    style={{ background: t.colors.editorBackground }}
                  />
                  <span
                    className="h-1.5"
                    style={{ background: t.colors.statusBarBackground }}
                  />
                </span>
              </span>

              <span className="flex flex-col">
                <span className="text-sm font-medium">{t.label}</span>
                <span className="text-xs">{t.description}</span>
              </span>
            </span>
            {selected ? (
              <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme: <span className="font-medium text-foreground">{resolvedTheme}</span>
      </p>
    </div>
  );
}

