import { describe, expect, it } from "vitest";

import {
  CSS_PROPERTY_MAP,
  getBuiltInThemes,
  getThemeById,
  isThemeId,
  type ThemeColors,
} from "./theme";

describe("isThemeId", () => {
  it("returns true for valid theme IDs", () => {
    expect(isThemeId("t3-dark")).toBe(true);
    expect(isThemeId("t3-light")).toBe(true);
    expect(isThemeId("t3-midnight")).toBe(true);
  });

  it("returns false for invalid values", () => {
    expect(isThemeId("light")).toBe(false);
    expect(isThemeId("dark")).toBe(false);
    expect(isThemeId("system")).toBe(false);
    expect(isThemeId("")).toBe(false);
    expect(isThemeId(null)).toBe(false);
    expect(isThemeId(undefined)).toBe(false);
    expect(isThemeId(42)).toBe(false);
  });
});

describe("getBuiltInThemes", () => {
  it("returns exactly 3 themes", () => {
    expect(getBuiltInThemes()).toHaveLength(3);
  });

  it("includes t3-light, t3-dark, and t3-midnight", () => {
    const ids = getBuiltInThemes().map((t) => t.id);
    expect(ids).toContain("t3-light");
    expect(ids).toContain("t3-dark");
    expect(ids).toContain("t3-midnight");
  });

  it("marks only t3-light as not dark", () => {
    for (const theme of getBuiltInThemes()) {
      if (theme.id === "t3-light") {
        expect(theme.isDark).toBe(false);
      } else {
        expect(theme.isDark).toBe(true);
      }
    }
  });

  it("returns the same array reference on repeated calls", () => {
    expect(getBuiltInThemes()).toBe(getBuiltInThemes());
  });
});

describe("getThemeById", () => {
  it("returns matching theme for each valid ID", () => {
    for (const theme of getBuiltInThemes()) {
      const found = getThemeById(theme.id);
      expect(found).toBeDefined();
      expect(found!.id).toBe(theme.id);
    }
  });

  it("returns the midnight theme with correct metadata", () => {
    const theme = getThemeById("t3-midnight");
    expect(theme).toBeDefined();
    expect(theme!.id).toBe("t3-midnight");
    expect(theme!.label).toBe("Midnight");
    expect(theme!.isDark).toBe(true);
  });

  it("returns undefined for unknown IDs", () => {
    // @ts-expect-error testing invalid input at runtime
    expect(getThemeById("nonexistent")).toBeUndefined();
  });
});

describe("CSS_PROPERTY_MAP", () => {
  it("has an entry for every ThemeColors key", () => {
    const theme = getThemeById("t3-dark")!;
    const colorKeys = Object.keys(theme.colors) as Array<keyof ThemeColors>;
    for (const key of colorKeys) {
      expect(CSS_PROPERTY_MAP[key]).toBeDefined();
      expect(CSS_PROPERTY_MAP[key]).toMatch(/^--/);
    }
  });

  it("maps camelCase keys to kebab-case CSS properties", () => {
    expect(CSS_PROPERTY_MAP.background).toBe("--background");
    expect(CSS_PROPERTY_MAP.primaryForeground).toBe("--primary-foreground");
    expect(CSS_PROPERTY_MAP.sidebarBackground).toBe("--sidebar-background");
    expect(CSS_PROPERTY_MAP.statusBarForeground).toBe("--status-bar-foreground");
    expect(CSS_PROPERTY_MAP.terminalBackground).toBe("--terminal-background");
    expect(CSS_PROPERTY_MAP.editorForeground).toBe("--editor-foreground");
  });
});

describe("theme color completeness", () => {
  it("every theme defines all required color keys", () => {
    const requiredKeys = Object.keys(CSS_PROPERTY_MAP) as Array<keyof ThemeColors>;
    for (const theme of getBuiltInThemes()) {
      for (const key of requiredKeys) {
        expect(theme.colors[key], `${theme.id} missing color: ${key}`).toBeTruthy();
      }
    }
  });

  it("every color value is a non-empty string", () => {
    for (const theme of getBuiltInThemes()) {
      for (const [key, value] of Object.entries(theme.colors)) {
        expect(typeof value, `${theme.id}.${key} should be a string`).toBe("string");
        expect(value.length, `${theme.id}.${key} should not be empty`).toBeGreaterThan(0);
      }
    }
  });
});

